  "processingConfig": {
    "version": 2,
    "taxonomyNotes": "Top-level categories are broad, multi-label buckets. Subtypes refine within each top-level. Attributes capture cross-cutting signals (e.g., urgency, explicitness).",
    "settings": {
      "initialization": {
        "applyHardAssertions": true,
        "seedCategoryScores": true
      },
      "ruleScoring": {
        "useLexicalPatterns": true,
        "applySubtypeRules": true,
        "boundedAggregation": true,
        "tuningParameters": {
          "KHigh": 1,
          "KMedium": 0.7,
          "KLow": 0.3,
          "aggregationCap": 1
        }
      },
      "attributeProcessing": {
        "detectSelfSent": true,
        "resolveDomains": true,
        "deriveContextFlags": true
      },
      "attributeInfluence": {
        "applyBonuses": true,
        "applyPenalties": true,
        "enforceCaps": true,
        "tuningParameters": {
          "bonusMultiplier": 1,
          "penaltyMultiplier": 1,
          "maxTotalBonus": 0.5,
          "maxTotalPenalty": 0.3
        }
      },
      "disambiguation": {
        "pairwiseAdjustments": true,
        "confidenceGapThreshold": 0.13333333333333333
      },
      "multiLabelSelection": {
        "maxLabels": 3,
        "minSecondaryConfidence": 0.5333333333333333,
        "allowedCombinations": ["financial+actionable"]
      },
      "aiRouting": {
        "highConfidenceThreshold": 1,
        "aiRequiredThreshold": 0.8,
        "skipAiConditions": ["hardAssertion"]
      },
      "performance": {
        "parallelProcessing": true,
        "maxParallelEmails": 10,
        "batchSize": 50,
        "enableCaching": true,
        "cacheTtlSeconds": 3600
      }
    },
    "categorySignals": {
      "financial": {
        "hardAssertions": {
          "fromDomainsRef": {
            "sourceGroup": "financial",
            "confidence": "high"
          },
          "subjectPrefixes": [
            "Your statement is ready",
            "Monthly statement",
            "Account statement",
            "Important account alert"
          ]
        },
        "strongIndicators": {
          "fromDomainsRef": {
            "sourceGroup": "financial",
            "confidence": "medium"
          },
          "subjectContains": ["invoice", "receipt", "payment posted", "card purchase", "transaction alert"],
          "bodyContains": ["amount due", "invoice number", "due date", "posted to your account"]
        },
        "disambiguators": {
          "boostIfPresentAttributes": ["hasAmount"],
          "suppressIfBodyContains": ["unsubscribe", "sale ends"]
        }
      },
      "travel": {
        "hardAssertions": {
          "fromAddresses": [
            "noreply-travel@google.com",
            "itinerary@expedia.com",
            "itinerary@travelport.com",
            "confirmation@booking.com",
            "notifications@aa.com",
            "notifications@delta.com"
          ],
          "subjectPrefixes": [
            "Your tracked flight to",
            "Flight update",
            "Itinerary for",
            "Your booking confirmation",
            "Boarding pass"
          ]
        },
        "strongIndicators": {
          "subjectContains": [
            "boarding pass",
            "gate change",
            "flight delayed",
            "flight cancellation",
            "check-in reminder"
          ],
          "bodyContains": [
            "PNR",
            "confirmation number",
            "booking reference",
            "departure",
            "arrival gate",
            "seat number"
          ]
        },
        "disambiguators": {
          "boostIfAbsentCategories": ["commerceLogistics"],
          "suppressIfBodyContains": ["order shipped"]
        }
      }
    },
    "confidenceThresholds": {
      "highConfidence": 1,
      "mediumConfidence": 0.5333333333333333,
      "lowConfidence": 0.2,
      "aiClassificationRequired": 0.8,
      "manualReviewRequired": 0.2,
      "secondaryLabelMinGap": 0.13333333333333333
    },
    "multiLabelPolicy": {
      "maxTopLevelLabels": 3,
      "minConfidenceForAdditional": 0.4,
      "minDeltaPrimarySecondary": 0.13333333333333333,
      "allowFinancialActionableCopresence": true
    },
    "domainSignalOverrides": {
      "financial": {
        "hardInclude": [],
        "hardExclude": [],
        "strongInclude": [],
        "strongExclude": []
      }
    },
    "domainSignalResolution": {
      "mode": "runtimeResolved",
      "source": "config/domain-sources.json",
      "notes": "fromDomainsRef entries are materialized at load time via domainResolver; do not edit fromDomains arrays directly."
    },
    "topLevelCategories": {
