    "attributes": {
      "schema": {
        "explicitness": {
          "type": "enum",
          "values": ["explicit", "implicit"],
          "description": "Nature of action request if actionable."
        },
        "urgency": {
          "type": "enum",
          "values": ["none", "low", "medium", "high"],
          "description": "Relative urgency derived from language & deadlines."
        },
        "requiresAction": {
          "type": "boolean",
          "description": "Indicates email requires user action or response"
        },
        "hasAmount": {
          "type": "boolean",
          "description": "Email contains monetary amounts or financial figures"
        },
        "hasDueDate": {
          "type": "boolean",
          "description": "Email contains due date or payment deadline"
        },
        "trackingPresent": {
          "type": "boolean",
          "description": "Email contains package tracking information"
        },
        "deliveryPhase": {
          "type": "enum",
          "values": ["preShipment", "inTransit", "outForDelivery", "delivered", "exception"],
          "description": "Logistics phase when commerceLogistics present."
        },
        "unsubscribePresent": {
          "type": "boolean",
          "description": "Email contains unsubscribe link or preference management"
        },
        "cadence": {
          "type": "enum",
          "values": ["daily", "weekly", "monthly", "irregular"],
          "description": "Heuristic cadence for subscription content."
        },
        "selfSent": {
          "type": "boolean",
          "description": "Email sent exclusively from user to self (all recipients are user addresses). Derived logically; no pattern detector."
        },
        "fromFinancialInstitution": {
          "type": "boolean",
          "description": "Sender domain/address matches known financial institution list."
        },
        "financialInstitutionType": {
          "type": "enum",
          "values": ["bank", "card", "investment", "paymentProcessor"],
          "description": "Institution classification derived from domain list when fromFinancialInstitution is true."
        },
        "fromNewsletterSource": {
          "type": "boolean",
          "description": "Sender domain/address or List-Id matches curated newsletter source list."
        },
        "fromLogisticsCarrier": {
          "type": "boolean",
          "description": "Sender domain/address matches known logistics carrier or marketplace list."
        },
        "hasPropertyReference": {
          "type": "boolean",
          "description": "Email contains property or service address references"
        }
      },
      "detectors": [
        {
          "attribute": "hasAmount",
          "field": "body",
          "operation": "regexAny",
          "values": ["\\$\\d+", "USD", "amount due"]
        },
        {
          "attribute": "hasDueDate",
          "field": "body",
          "operation": "containsAny",
          "values": ["due by", "due on", "due date", "pay by", "payment due"]
        },
        {
          "attribute": "requiresAction",
          "field": "body",
          "operation": "containsAny",
          "values": ["please review", "action required", "respond", "reply", "follow up"]
        },
        {
          "attribute": "trackingPresent",
          "field": "body",
          "operation": "containsAny",
          "values": ["tracking number", "track your package"]
        },
        {
          "attribute": "unsubscribePresent",
          "field": "body",
          "operation": "containsAny",
          "values": ["unsubscribe", "manage preferences"]
        }
      ],
      "derived": {
        "selfSent": {
          "logic": "from.address in userAddresses AND all(to+cc+bcc) in userAddresses AND NOT headers['List-Id']",
          "notes": "Used to auto-derive personal.selfNote subtype when no stronger personal subtype matches."
        },
        "fromFinancialInstitution": {
          "logic": "baseDomain(from.address) in domainSources.financial.domains",
          "notes": "financialInstitutionType taken from domain metadata."
        },
        "fromNewsletterSource": {
          "logic": "baseDomain(from.address) in domainSources.newsletter.domains OR headers['List-Id'] present",
          "notes": "List-Id presence alone does not force newsletter if strong promotional patterns dominate."
        },
        "fromLogisticsCarrier": {
          "logic": "baseDomain(from.address) in domainSources.logistics.domains",
          "notes": "Used to boost commerceLogistics; does not override travel flight contexts."
        }
      },
      "attributeBonusMap": {
        "personal": {
          "selfSent": 1
        },
        "financial": {
          "fromFinancialInstitution": 0.8,
          "hasAmount": 0.4,
          "hasDueDate": 0.4
        },
        "subscriptionContent": {
          "fromNewsletterSource": 0.6,
          "cadence": 1
        },
        "actionable": {
          "requiresAction": 0.4,
          "explicitness": 0.6,
          "urgency": 0.4
        },
        "commerceLogistics": {
          "fromLogisticsCarrier": 0.8,
          "trackingPresent": 0.4
        }
      }
