          "```xml",
          "<ruleScores>",
          "{candidateCategories}",
          "</ruleScores>",
          "",
          "<extractedFeatures>",
          "{extractedFeatures}",
          "</extractedFeatures>",
          "```",
          "",
          "Email Context:",
          "From: {email.from}",
          "Subject: {email.subject}",
          "Body: {email.body}",
          "",
          "Apply thresholds and multi-label policy to provide final classification decisions."
        ]
      }
