   410→  if (hasListId) {
   411→    return {
   412→      attributeName: 'fromNewsletterSource',
   413→      attributeValue: true,
   414→      detectionMethod: 'derived',
   415→      detectionEvidence: 'List-Id header present',
   416→      confidence: 0.85,
   417→    };
   418→  }
   419→
   420→  return null;
   421→}
