   423→/**
   424→ * Derive fromLogisticsCarrier attribute
   425→ */
   426→function deriveFromLogisticsCarrier(
   427→  email: EmailMessage,
   428→  config: AttributeDetectionStageConfig
   429→): DetectedAttribute | null {
   430→  const fromAddress = email.from?.email?.toLowerCase();
   431→  if (!fromAddress) return null;
   432→
   433→  const fromDomain = extractBaseDomain(fromAddress);
   434→  const logisticsDomains = getLogisticsDomains(config);
   435→
