   449→/**
   450→ * Extract base domain from email address
   451→ */
   452→function extractBaseDomain(email: string): string {
   453→  const domainPart = email.split('@')[1];
   454→  if (!domainPart) return '';
   455→
   456→  // Handle subdomains - return main domain for common patterns
   457→  const parts = domainPart.split('.');
   458→  if (parts.length >= 2) {
   459→    return parts.slice(-2).join('.');
